module div_16bit(
    input clk,
    input rst,
    input sign,
    input [15:0] dividend,
    input [15:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

reg [3:0] cnt;
reg start_cnt;
reg [15:0] neg_divisor;
reg [15:0] sr;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        cnt <= 4'b0000;
        start_cnt <= 1'b0;
        neg_divisor <= 16'h0000;
        sr <= 16'h0000;
        res_valid <= 1'b0;
        result <= 16'h0000;
    end else begin
        if (opn_valid && !res_valid) begin
            cnt <= 4'b0001;
            start_cnt <= 1'b1;
            neg_divisor <= (sign && dividend[7]) ? {1'b1, ~divisor + 1'b1} : {1'b1, divisor};
            sr <= (sign && dividend[7]) ? {1'b1, ~dividend + 1'b1} : {1'b1, dividend};
        end
        if (start_cnt) begin
            if (cnt[3]) begin
                cnt <= 4'b0000;
                start_cnt <= 1'b0;
                sr <= {neg_divisor, sr[15:1]};
            end else begin
                cnt <= cnt + 4'b0001;
                start_cnt <= 1'b1;
                sr <= {neg_divisor, sr[15:1]};
            end
        end
        if (res_valid && res_ready) begin
            res_valid <= 1'b0;
        end else if (cnt[3]) begin
            res_valid <= 1'b1;
        end
    end
end

always @(*) begin
    if (sign && divisor[7]) begin
        result <= {sr[15:8], sr[7:0]};
    end else if (sign && dividend[7]) begin
        result <= {~sr[15:8] + 1'b1, sr[7:0]};
    end else if (divisor[7]) begin
        result <= {~sr[15:8] + 1'b1, ~sr[7:0] + 1'b1};
    end else begin
        result <= {sr[15:8], ~sr[7:0] + 1'b1};
    end
end

endmodule
